import React, { useEffect, useRef, useState } from 'react';
import {
  Stage,
  Layer,
  Group,
  Image as KonvaImage,
  Rect,
  Line,
  Circle,
  Ellipse,
  Arrow,
} from 'react-konva';
import './AnnotationCanvas.css';

export default function AnnotationCanvas({
  fileUrl,
  annotations,
  onAnnotationsChange,
  selectedTool,
  scale,
  onWheelZoom,
  activeLabelColor,
  onFinishShape,
}) {
  const stageRef = useRef(null);
  const containerRef = useRef(null);

  const [dims, setDims] = useState({ width: 0, height: 0 });
  const [konvaImg, setKonvaImg] = useState(null);

  // Master group offset (image panning)
  const [imagePos, setImagePos] = useState({ x: 0, y: 0 });

  // In-progress shapes
  const [newBox, setNewBox] = useState(null);
  const [tempPoints, setTempPoints] = useState([]);
  const [drawingPolygon, setDrawingPolygon] = useState(false);
  const [tempPolyline, setTempPolyline] = useState([]);
  const [drawingPolyline, setDrawingPolyline] = useState(false);
  const [newEllipse, setNewEllipse] = useState(null);

  useEffect(() => {
    const handleResize = () => {
      if (!containerRef.current) return;
      setDims({
        width: containerRef.current.offsetWidth,
        height: containerRef.current.offsetHeight,
      });
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // Load image
  useEffect(() => {
    if (!fileUrl) return;
    const img = new window.Image();
    img.src = fileUrl;
    img.onload = () => {
      setKonvaImg(img);
      setImagePos({ x: 0, y: 0 });
    };
    img.onerror = () => console.error('Could not load image:', fileUrl);
  }, [fileUrl]);

  // For coordinate conversions
  const getGroupPos = (evt) => {
    const group = stageRef.current?.findOne('#anno-group');
    return group ? group.getRelativePointerPosition() : null;
  };

  // Flatten array of {x,y}
  const flattenPoints = (pts) => pts.flatMap((p) => [p.x, p.y]);

  // Helper to check if shape is outside image bounds
  const shapeBoundingBox = (ann) => {
    if (ann.type === 'bbox') {
      return {
        x1: ann.x,
        y1: ann.y,
        x2: ann.x + ann.width,
        y2: ann.y + ann.height,
      };
    } else if (ann.type === 'ellipse') {
      return {
        x1: ann.x - ann.radiusX,
        y1: ann.y - ann.radiusY,
        x2: ann.x + ann.radiusX,
        y2: ann.y + ann.radiusY,
      };
    } else if (ann.type === 'polygon' || ann.type === 'polyline') {
      let minX = Infinity,
        minY = Infinity,
        maxX = -Infinity,
        maxY = -Infinity;
      ann.points.forEach((pt) => {
        if (pt.x < minX) minX = pt.x;
        if (pt.y < minY) minY = pt.y;
        if (pt.x > maxX) maxX = pt.x;
        if (pt.y > maxY) maxY = pt.y;
      });
      return { x1: minX, y1: minY, x2: maxX, y2: maxY };
    } else if (ann.type === 'point') {
      return {
        x1: ann.x,
        y1: ann.y,
        x2: ann.x,
        y2: ann.y,
      };
    }
    return null;
  };
  const isOutsideImage = (ann) => {
    if (!konvaImg) return false;
    const box = shapeBoundingBox(ann);
    if (!box) return false;
    const { x1, y1, x2, y2 } = box;
    if (x2 < 0 || x1 > konvaImg.width || y2 < 0 || y1 > konvaImg.height) {
      return true;
    }
    return false;
  };

  // -------------- Creating BBox --------------
  const startBox = (pos) => {
    setNewBox({ x: pos.x, y: pos.y, width: 0, height: 0 });
  };
  const updateBox = (pos) => {
    if (!newBox) return;
    setNewBox({
      ...newBox,
      width: pos.x - newBox.x,
      height: pos.y - newBox.y,
    });
  };
  const finalizeBox = () => {
    if (!newBox) return;
    const newAnn = { type: 'bbox', ...newBox, label: '' };
    if (!isOutsideImage(newAnn)) {
      onAnnotationsChange([...annotations, newAnn]);
    }
    setNewBox(null);
    onFinishShape && onFinishShape();
  };

  // -------------- Creating Polygon --------------
  const addPolygonPoint = (pos) => {
    setTempPoints((prev) => [...prev, pos]);
    setDrawingPolygon(true);
  };
  const finalizePolygon = () => {
    if (tempPoints.length >= 3) {
      const newAnn = { type: 'polygon', points: tempPoints, label: '' };
      if (!isOutsideImage(newAnn)) {
        onAnnotationsChange([...annotations, newAnn]);
      }
    }
    setTempPoints([]);
    setDrawingPolygon(false);
    onFinishShape && onFinishShape();
  };

  // -------------- Creating Polyline --------------
  const addPolylinePoint = (pos) => {
    setTempPolyline((prev) => [...prev, pos]);
    setDrawingPolyline(true);
  };
  const finalizePolyline = () => {
    if (tempPolyline.length >= 2) {
      const newAnn = { type: 'polyline', points: tempPolyline, label: '' };
      if (!isOutsideImage(newAnn)) {
        onAnnotationsChange([...annotations, newAnn]);
      }
    }
    setTempPolyline([]);
    setDrawingPolyline(false);
    onFinishShape && onFinishShape();
  };

  // -------------- Creating Point --------------
  const addPoint = (pos) => {
    const newAnn = { type: 'point', x: pos.x, y: pos.y, label: '' };
    if (!isOutsideImage(newAnn)) {
      onAnnotationsChange([...annotations, newAnn]);
    }
    onFinishShape && onFinishShape();
  };

  // -------------- Creating Ellipse --------------
  const startEllipse = (pos) => {
    setNewEllipse({
      type: 'ellipse',
      x: pos.x,
      y: pos.y,
      radiusX: 0,
      radiusY: 0,
      rotation: 0,
      label: '',
    });
  };
  const updateEllipse = (pos) => {
    if (!newEllipse) return;
    const rx = Math.abs(pos.x - newEllipse.x);
    const ry = Math.abs(pos.y - newEllipse.y);
    setNewEllipse({
      ...newEllipse,
      radiusX: rx,
      radiusY: ry,
    });
  };
  const finalizeEllipse = () => {
    if (!newEllipse) return;
    if (!isOutsideImage(newEllipse)) {
      onAnnotationsChange([...annotations, { ...newEllipse }]);
    }
    setNewEllipse(null);
    onFinishShape && onFinishShape();
  };

  // -------------- Handle Mouse / Double-Click --------------
  const handleMouseDown = (evt) => {
    if (selectedTool === 'move') {
      // Do nothing => let group handle panning if user drags empty space
      return;
    }
    const pos = getGroupPos(evt);
    if (!pos) return;

    if (selectedTool === 'bbox') {
      startBox(pos);
    } else if (selectedTool === 'polygon') {
      addPolygonPoint(pos);
    } else if (selectedTool === 'polyline') {
      addPolylinePoint(pos);
    } else if (selectedTool === 'point') {
      addPoint(pos);
    } else if (selectedTool === 'ellipse') {
      startEllipse(pos);
    }
  };
  const handleMouseMove = (evt) => {
    if (selectedTool === 'bbox' && newBox) {
      const pos = getGroupPos(evt);
      if (pos) updateBox(pos);
    } else if (selectedTool === 'ellipse' && newEllipse) {
      const pos = getGroupPos(evt);
      if (pos) updateEllipse(pos);
    }
  };
  const handleMouseUp = () => {
    if (selectedTool === 'bbox' && newBox) {
      finalizeBox();
    } else if (selectedTool === 'ellipse' && newEllipse) {
      finalizeEllipse();
    }
  };
  const handleDblClick = () => {
    if (selectedTool === 'polygon' && drawingPolygon) {
      finalizePolygon();
    } else if (selectedTool === 'polyline' && drawingPolyline) {
      finalizePolyline();
    }
  };

  // -------------- Cancel in-progress shape on ESC --------------
  useEffect(() => {
    const onCancelAnnotation = () => {
      setNewBox(null);
      setTempPoints([]);
      setDrawingPolygon(false);
      setTempPolyline([]);
      setDrawingPolyline(false);
      setNewEllipse(null);
    };
    window.addEventListener('cancel-annotation', onCancelAnnotation);
    return () => window.removeEventListener('cancel-annotation', onCancelAnnotation);
  }, []);

  // -------------- Wheel Zoom --------------
  const handleWheel = (evt) => {
    evt.evt.preventDefault();
    onWheelZoom(evt.evt.deltaY);
  };

  // --- Move BBox, Ellipse, Point (single-shape) are replaced by new approach for BBox. We'll keep ellipse/point as is. ---
  const handleEllipseDragEnd = (index, e) => {
    const { x, y } = e.target.position();
    const updated = [...annotations];
    updated[index] = { ...updated[index], x, y };
    if (isOutsideImage(updated[index])) {
      updated.splice(index, 1);
    }
    onAnnotationsChange(updated);
  };
  const handlePointDragEnd = (index, e) => {
    const { x, y } = e.target.position();
    const updated = [...annotations];
    updated[index] = { ...updated[index], x, y };
    if (isOutsideImage(updated[index])) {
      updated.splice(index, 1);
    }
    onAnnotationsChange(updated);
  };

  // -------------- Move Polygon / Polyline (all points) --------------
  function DraggablePolygon({ ann, index }) {
    const groupRef = useRef(null);

    const handleGroupDragStart = (e) => {
      e.cancelBubble = true;
    };
    const handleGroupDragMove = (e) => {
      e.cancelBubble = true;
    };
    const handleGroupDragEnd = (e) => {
      e.cancelBubble = true;
      const { x, y } = e.target.position();
      // Shift all points by (x, y)
      const newPoints = ann.points.map((pt) => ({
        x: pt.x + x,
        y: pt.y + y,
      }));
      const updated = [...annotations];
      updated[index] = { ...ann, points: newPoints };
      // Reset group position
      e.target.position({ x: 0, y: 0 });
      if (isOutsideImage(updated[index])) {
        updated.splice(index, 1);
      }
      onAnnotationsChange(updated);
    };

    const pts = flattenPoints(ann.points);
    const firstPt = ann.points[0];
    const secondPt = ann.points[1] || { x: firstPt.x + 10, y: firstPt.y };

    return (
      <Group
        draggable={true}
        ref={groupRef}
        onDragStart={handleGroupDragStart}
        onDragMove={handleGroupDragMove}
        onDragEnd={handleGroupDragEnd}
        onMouseDown={(e) => (e.cancelBubble = true)}
      >
        <Line
          points={pts}
          fill={activeLabelColor + '55'}
          stroke={activeLabelColor}
          strokeWidth={2 / scale}
          closed
        />
        <Arrow
          points={[secondPt.x, secondPt.y, firstPt.x, firstPt.y]}
          fill={activeLabelColor}
          stroke={activeLabelColor}
          strokeWidth={2 / scale}
          pointerLength={10 / scale}
          pointerWidth={8 / scale}
        />
      </Group>
    );
  }

  function DraggablePolyline({ ann, index }) {
    const groupRef = useRef(null);

    const handleGroupDragStart = (e) => {
      e.cancelBubble = true;
    };
    const handleGroupDragMove = (e) => {
      e.cancelBubble = true;
    };
    const handleGroupDragEnd = (e) => {
      e.cancelBubble = true;
      const { x, y } = e.target.position();
      const newPoints = ann.points.map((pt) => ({
        x: pt.x + x,
        y: pt.y + y,
      }));
      const updated = [...annotations];
      updated[index] = { ...ann, points: newPoints };
      // Reset group position
      e.target.position({ x: 0, y: 0 });
      if (isOutsideImage(updated[index])) {
        updated.splice(index, 1);
      }
      onAnnotationsChange(updated);
    };

    const pts = flattenPoints(ann.points);
    const firstPt = ann.points[0];
    const secondPt = ann.points[1] || { x: firstPt.x + 10, y: firstPt.y };

    return (
      <Group
        draggable={true}
        ref={groupRef}
        onDragStart={handleGroupDragStart}
        onDragMove={handleGroupDragMove}
        onDragEnd={handleGroupDragEnd}
        onMouseDown={(e) => (e.cancelBubble = true)}
      >
        <Line
          points={pts}
          stroke={activeLabelColor}
          strokeWidth={2 / scale}
          closed={false}
        />
        <Arrow
          points={[secondPt.x, secondPt.y, firstPt.x, firstPt.y]}
          fill={activeLabelColor}
          stroke={activeLabelColor}
          strokeWidth={2 / scale}
          pointerLength={10 / scale}
          pointerWidth={8 / scale}
        />
      </Group>
    );
  }

  // -------------- DRAGGABLE-RESIZABLE BBOX COMPONENT --------------
  function DraggableResizableBbox({
    ann,
    index,
    annotations,
    onAnnotationsChange,
    isOutsideImage,
    activeLabelColor,
    scale,
  }) {
    const groupRef = useRef(null);
    const handleSize = 8 / scale; // corner-handle size

    // === Group (the entire bounding box) drag handlers ===
    const handleGroupDragStart = (e) => {
      e.cancelBubble = true;
    };
    const handleGroupDragMove = (e) => {
      e.cancelBubble = true;
    };
    const handleGroupDragEnd = (e) => {
      e.cancelBubble = true;
      const { x, y } = e.target.position();
      // The user moved the entire bounding box from (ann.x, ann.y) to (x, y).
      // We'll update x,y while width,height remain the same.
      const updatedBbox = {
        ...ann,
        x: ann.x + x,
        y: ann.y + y,
      };

      const updated = [...annotations];
      updated[index] = updatedBbox;

      if (isOutsideImage(updatedBbox)) {
        updated.splice(index, 1);
      }
      onAnnotationsChange(updated);

      // Reset the group's position so next drag starts fresh:
      e.target.position({ x: 0, y: 0 });
    };

    // === Corner drag logic ===
    // Each corner has a "role": 'topLeft','topRight','bottomLeft','bottomRight'.
    const handleCornerDragEnd = (cornerRole, e) => {
      e.cancelBubble = true;
      const { x: cornerNewX, y: cornerNewY } = e.target.position();

      // Original corners before drag
      const topLeft = { x: ann.x, y: ann.y };
      const bottomRight = {
        x: ann.x + ann.width,
        y: ann.y + ann.height,
      };

      let newTopLeft = { ...topLeft };
      let newBottomRight = { ...bottomRight };

      if (cornerRole === 'topLeft') {
        newTopLeft = { x: topLeft.x + cornerNewX, y: topLeft.y + cornerNewY };
      } else if (cornerRole === 'topRight') {
        newTopLeft = { x: topLeft.x, y: topLeft.y + cornerNewY };
        newBottomRight = {
          x: bottomRight.x + cornerNewX,
          y: bottomRight.y,
        };
      } else if (cornerRole === 'bottomLeft') {
        newTopLeft = { x: topLeft.x + cornerNewX, y: topLeft.y };
        newBottomRight = {
          x: bottomRight.x,
          y: bottomRight.y + cornerNewY,
        };
      } else if (cornerRole === 'bottomRight') {
        newBottomRight = {
          x: bottomRight.x + cornerNewX,
          y: bottomRight.y + cornerNewY,
        };
      }

      // Compute final bounding box so x,y is always top-left
      const minX = Math.min(newTopLeft.x, newBottomRight.x);
      const maxX = Math.max(newTopLeft.x, newBottomRight.x);
      const minY = Math.min(newTopLeft.y, newBottomRight.y);
      const maxY = Math.max(newTopLeft.y, newBottomRight.y);

      const newBbox = {
        ...ann,
        x: minX,
        y: minY,
        width: maxX - minX,
        height: maxY - minY,
      };

      const updated = [...annotations];
      updated[index] = newBbox;
      if (isOutsideImage(newBbox)) {
        updated.splice(index, 1);
      }
      onAnnotationsChange(updated);

      // Reset handle’s position
      e.target.position({ x: 0, y: 0 });
    };

    // For convenience, define the corners:
    const x1 = ann.x;
    const y1 = ann.y;
    const x2 = ann.x + ann.width;
    const y2 = ann.y + ann.height;

    const cornerPositions = {
      topLeft: { x: x1, y: y1 },
      topRight: { x: x2, y: y1 },
      bottomLeft: { x: x1, y: y2 },
      bottomRight: { x: x2, y: y2 },
    };

    // Corner handle sub-component
    const CornerHandle = ({ cornerRole, cx, cy }) => (
      <Rect
        x={cx - handleSize / 2}
        y={cy - handleSize / 2}
        width={handleSize}
        height={handleSize}
        fill={activeLabelColor}
        draggable
        onMouseDown={(ev) => (ev.cancelBubble = true)}
        onDragStart={(ev) => (ev.cancelBubble = true)}
        onDragMove={(ev) => (ev.cancelBubble = true)}
        onDragEnd={(ev) => handleCornerDragEnd(cornerRole, ev)}
      />
    );

    const fillColor = activeLabelColor + '55';

    return (
      <Group
        ref={groupRef}
        draggable
        onDragStart={handleGroupDragStart}
        onDragMove={handleGroupDragMove}
        onDragEnd={handleGroupDragEnd}
      // We keep the group at (0,0); the bounding box is drawn at (ann.x, ann.y).
      >
        {/* Main BBox rect */}
        <Rect
          x={ann.x}
          y={ann.y}
          width={ann.width}
          height={ann.height}
          fill={fillColor}
          stroke={activeLabelColor}
          strokeWidth={2 / scale}
          onMouseDown={(e) => (e.cancelBubble = true)}
          onDragStart={(e) => (e.cancelBubble = true)}
          onDragMove={(e) => (e.cancelBubble = true)}
        />

        {/* 4 corner handles */}
        <CornerHandle
          cornerRole="topLeft"
          cx={cornerPositions.topLeft.x}
          cy={cornerPositions.topLeft.y}
        />
        <CornerHandle
          cornerRole="topRight"
          cx={cornerPositions.topRight.x}
          cy={cornerPositions.topRight.y}
        />
        <CornerHandle
          cornerRole="bottomLeft"
          cx={cornerPositions.bottomLeft.x}
          cy={cornerPositions.bottomLeft.y}
        />
        <CornerHandle
          cornerRole="bottomRight"
          cx={cornerPositions.bottomRight.x}
          cy={cornerPositions.bottomRight.y}
        />
      </Group>
    );
  }

  // -------------- RENDER --------------
  const fillColor = activeLabelColor + '55'; // used for in-progress shapes

  return (
    <div className="canvas-container" ref={containerRef}>
      <Stage
        ref={stageRef}
        width={dims.width}
        height={dims.height}
        scaleX={scale}
        scaleY={scale}
        style={{ background: '#dfe6e9' }}
        onWheel={handleWheel}
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onDblClick={handleDblClick}
      >
        <Layer>
          <Group
            id="anno-group"
            draggable={selectedTool === 'move'}
            x={imagePos.x}
            y={imagePos.y}
            onDragEnd={(e) => {
              // user panned the entire image
              setImagePos({ x: e.target.x(), y: e.target.y() });
            }}
          >
            {konvaImg && (
              <KonvaImage
                image={konvaImg}
                width={konvaImg.width}
                height={konvaImg.height}
              />
            )}

            {/* Existing shapes */}
            {annotations.map((ann, i) => {
              if (ann.type === 'bbox') {
                // Use our new DRAGGABLE-RESIZABLE BBOX
                return (
                  <DraggableResizableBbox
                    key={i}
                    ann={ann}
                    index={i}
                    annotations={annotations}
                    onAnnotationsChange={onAnnotationsChange}
                    isOutsideImage={isOutsideImage}
                    activeLabelColor={activeLabelColor}
                    scale={scale}
                  />
                );
              } else if (ann.type === 'ellipse') {
                return (
                  <Ellipse
                    key={i}
                    x={ann.x}
                    y={ann.y}
                    radiusX={ann.radiusX}
                    radiusY={ann.radiusY}
                    rotation={ann.rotation || 0}
                    fill={fillColor}
                    stroke={activeLabelColor}
                    strokeWidth={2 / scale}
                    draggable={true}
                    onMouseDown={(e) => (e.cancelBubble = true)}
                    onDragStart={(e) => (e.cancelBubble = true)}
                    onDragMove={(e) => (e.cancelBubble = true)}
                    onDragEnd={(e) => handleEllipseDragEnd(i, e)}
                  />
                );
              } else if (ann.type === 'point') {
                return (
                  <Circle
                    key={i}
                    x={ann.x}
                    y={ann.y}
                    radius={6 / scale}
                    fill={activeLabelColor}
                    draggable={true}
                    onMouseDown={(e) => (e.cancelBubble = true)}
                    onDragStart={(e) => (e.cancelBubble = true)}
                    onDragMove={(e) => (e.cancelBubble = true)}
                    onDragEnd={(e) => handlePointDragEnd(i, e)}
                  />
                );
              } else if (ann.type === 'polygon') {
                return (
                  <DraggablePolygon
                    key={i}
                    ann={ann}
                    index={i}
                  />
                );
              } else if (ann.type === 'polyline') {
                return (
                  <DraggablePolyline
                    key={i}
                    ann={ann}
                    index={i}
                  />
                );
              }
              return null;
            })}

            {/* In-progress BBox */}
            {newBox && selectedTool === 'bbox' && (
              <Rect
                x={newBox.x}
                y={newBox.y}
                width={newBox.width}
                height={newBox.height}
                fill={fillColor}
                stroke={activeLabelColor}
                strokeWidth={2 / scale}
              />
            )}

            {/* In-progress Polygon */}
            {drawingPolygon && tempPoints.length > 1 && selectedTool === 'polygon' && (
              <Line
                points={flattenPoints([...tempPoints, tempPoints[0]])}
                fill={fillColor}
                stroke={activeLabelColor}
                strokeWidth={2 / scale}
                closed
              />
            )}

            {/* In-progress Polyline */}
            {drawingPolyline && tempPolyline.length > 1 && selectedTool === 'polyline' && (
              <Line
                points={flattenPoints(tempPolyline)}
                stroke={activeLabelColor}
                strokeWidth={2 / scale}
                closed={false}
              />
            )}

            {/* In-progress Ellipse */}
            {newEllipse && selectedTool === 'ellipse' && (
              <Ellipse
                x={newEllipse.x}
                y={newEllipse.y}
                radiusX={newEllipse.radiusX}
                radiusY={newEllipse.radiusY}
                rotation={0}
                fill={fillColor}
                stroke={activeLabelColor}
                strokeWidth={2 / scale}
              />
            )}
          </Group>
        </Layer>
      </Stage>
    </div>
  );
}
